"""Pure position state: buckets, filters, orphan rules — no I/O."""

from __future__ import annotations

from relocation_jobs.v2.positions.types import PositionBucket, PositionFilters, TrackingSnapshot


def route_bucket(
    tracking: TrackingSnapshot,
    *,
    wrong_location: bool = False,
) -> PositionBucket:
    """
    Assign a catalog job to exactly one panel bucket (BUSINESS_RULES §10).

    Rejected roles never land in the main board. Not-for-me (including wrong
    location on read) routes to ``not_for_me_jobs``.
    """
    if tracking.not_for_me or wrong_location:
        return PositionBucket.NOT_FOR_ME
    if tracking.rejected:
        return PositionBucket.REJECTED
    return PositionBucket.JOBS


def qualifies_for_orphan_reinject(tracking: TrackingSnapshot) -> bool:
    """Orphan reinjection — BUSINESS_RULES §11."""
    if tracking.not_for_me:
        return False
    return tracking.applied or tracking.rejected or tracking.looking_to_apply


def passes_position_filters(
    tracking: TrackingSnapshot,
    filters: PositionFilters,
) -> bool:
    """Whether a main-board row passes position filters — BUSINESS_RULES §13."""
    if filters.hide_applied and tracking.applied:
        return False
    if filters.hide_rejected and tracking.rejected:
        return False
    if filters.applied_only and not tracking.applied:
        return False
    if filters.rejected_only and not tracking.rejected:
        return False
    if filters.looking_to_apply_only and not tracking.looking_to_apply:
        return False
    return True

