"""Per-user tracking flags stored in ``job_tracking`` (orthogonal to panel bucket)."""

from __future__ import annotations

from relocation_jobs.schemas.common import BaseSchema


def as_tracking_bool(value) -> bool:
    if value is None:
        return False
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    if isinstance(value, str):
        return value.strip().lower() not in ("", "0", "false", "no", "off")
    return bool(value)


class TrackingFlags(BaseSchema):
    """
    Flags overlayed onto catalog jobs at read time.

    These are independent toggles in the DB; panel bucket is derived separately
    via ``derive_bucket`` (see ``buckets.py``).
    """

    applied: bool = False
    rejected: bool = False
    not_for_me: bool = False
    looking_to_apply: bool = False
    waiting_referral: bool = False
    seen: bool = False
    not_for_me_reason: str = ""

    @classmethod
    def from_row(cls, row: dict | None) -> TrackingFlags:
        if not row:
            return cls()
        return cls(
            applied=bool(row.get("applied")),
            rejected=as_tracking_bool(row.get("rejected")),
            not_for_me=bool(row.get("not_for_me")),
            looking_to_apply=bool(row.get("looking_to_apply")),
            waiting_referral=bool(row.get("waiting_referral")),
            seen=as_tracking_bool(row.get("seen")),
            not_for_me_reason=(row.get("not_for_me_reason") or "").strip(),
        )

    def has_active_tracking(self) -> bool:
        """True when user has meaningful state worth orphan reinjection (§11)."""
        if self.not_for_me:
            return False
        return self.applied or self.rejected or self.looking_to_apply

