"""Read-model: tracking flags + derived panel bucket."""

from __future__ import annotations

from relocation_jobs.schemas.common import BaseSchema
from relocation_jobs.v2.positions.buckets import PositionBucket, derive_bucket
from relocation_jobs.v2.positions.tracking import TrackingFlags


class PositionView(BaseSchema):
    """Single object for panel assembly: flags from DB + routed bucket."""

    flags: TrackingFlags
    bucket: PositionBucket

    @classmethod
    def from_row(
        cls,
        row: dict | None,
        *,
        wrong_location: bool = False,
    ) -> PositionView:
        flags = TrackingFlags.from_row(row)
        return cls(
            flags=flags,
            bucket=derive_bucket(flags, wrong_location=wrong_location),
        )

    @property
    def on_main_board(self) -> bool:
        return self.bucket == PositionBucket.JOBS

