@dataclass
class PanelContext:
    user_id: int | None
    job_tracking: dict = field(default_factory=dict)
    company_tracking: dict = field(default_factory=dict)
    status_history: dict = field(default_factory=dict)
    country_cache: dict[str, dict] = field(default_factory=dict)


def load_context(user_id: int | None) -> PanelContext:
    if not user_id:
        return PanelContext(user_id=None)
    return PanelContext(
        user_id=user_id,
        job_tracking=load_job_tracking(user_id),
        company_tracking=load_company_tracking(user_id),
        status_history=load_job_status_history(user_id),
    )

