        "applied_events": hist.get("applied_events") or [],
        "not_for_me": False,
        "not_for_me_date": "",
        "rejected": rejected,
        "rejected_date": _display_status_date(track.get("rejected_date", "") if rejected else "", hist["rejected"]),
