from __future__ import annotations

from collections.abc import Callable
from dataclasses import dataclass

from relocation_jobs.v2.positions.types import PositionBucket, PositionFilters, PositionView, TrackingFlags


@dataclass(frozen=True)
class _BucketContext:
    flags: TrackingFlags
    wrong_location: bool


# First match wins — documents read-path priority (rule 10: not-for-me, then rejected).
_BUCKET_RULES: tuple[tuple[Callable[[_BucketContext], bool], PositionBucket], ...] = (
    (lambda ctx: ctx.flags.not_for_me or ctx.wrong_location, PositionBucket.NOT_FOR_ME),
    (lambda ctx: ctx.flags.rejected, PositionBucket.REJECTED),
)


def derive_bucket(
    flags: TrackingFlags,
    *,
    wrong_location: bool = False,
) -> PositionBucket:
    ctx = _BucketContext(flags, wrong_location)
    for matches, bucket in _BUCKET_RULES:
        if matches(ctx):
            return bucket
    return PositionBucket.JOBS


def orphan_reinject_eligible(flags: TrackingFlags) -> bool:
    return flags.has_active_tracking()


def position_view_from_row(
    row: dict | None,
    *,
    wrong_location: bool = False,
) -> PositionView:
    flags = TrackingFlags.from_row(row)
    return PositionView(
        flags=flags,
        bucket=derive_bucket(flags, wrong_location=wrong_location),
    )


# Each rule returns True when the position may stay visible under that filter.
_POSITION_FILTER_RULES: tuple[
    Callable[[TrackingFlags, PositionFilters], bool],
    ...,
] = (
    lambda flags, filters: not (filters.hide_applied and flags.applied),
    lambda flags, filters: not (filters.hide_rejected and flags.rejected),
    lambda flags, filters: not (filters.applied_only and not flags.applied),
    lambda flags, filters: not (filters.rejected_only and not flags.rejected),
    lambda flags, filters: not (filters.looking_to_apply_only and not flags.looking_to_apply),
)


def passes_position_filters(flags: TrackingFlags, filters: PositionFilters) -> bool:
    return all(rule(flags, filters) for rule in _POSITION_FILTER_RULES)

