from relocation_jobs.v2.scrape.boards.greenhouse import fetch_greenhouse_board

_SUPPORTED_ATS = frozenset({"greenhouse", "greenhouse_eu"})


class UnsupportedAtsTypeError(LookupError):
    def __init__(self, ats_type: str):
        self.ats_type = ats_type
        super().__init__(f"Unsupported ATS type for v2 board fetch: {ats_type or 'unknown'}")


async def fetch_ats_board(client, company: dict, **kwargs) -> list[dict]:
    """Fetch raw listings for a company with a cached ATS type and URL."""
    ats_type = (company.get("ats_type") or "").strip().lower()
    board_url = (company.get("ats_url") or company.get("careers_url") or "").strip()
    if not board_url:
        raise LookupError(f"No careers or ATS URL for {company.get('name') or 'company'}")

    if ats_type in _SUPPORTED_ATS:
        return await fetch_greenhouse_board(client, board_url)

    if not ats_type:
        raise LookupError(
            f"No cached ATS type for {company.get('name') or 'company'} — detect ATS before fetch"
        )
    raise UnsupportedAtsTypeError(ats_type)

from __future__ import annotations

import os

from flask import jsonify, request

from relocation_jobs.core.auth import login_required
from relocation_jobs.core.location_tags import COUNTRY_LABELS
from relocation_jobs.core.paths import COUNTRY_ARCHIVE_FILENAMES, SUPPORTED_COUNTRIES
from relocation_jobs.v2.fetch.runner import run_single_company_fetch


def scrape_enabled() -> bool:
    return os.environ.get("PANEL_SCRAPE_ENABLED", "1").lower() not in ("0", "false", "no")


def register(app):
    @app.post("/api/companies/fetch")
    @login_required
    def api_companies_fetch():
        if not scrape_enabled():
            return jsonify({
                "error": (
                    "Scraping is disabled on this host. "
                    "Run scrapes locally, then sync catalog to Postgres."
                ),
            }), 503

        body = request.get_json(silent=True) or {}
        country = (body.get("country") or "").strip().lower()
        company = (body.get("company") or "").strip()

        if not country or country == "all":
            return jsonify({"error": "country is required (not 'all')"}), 400
        if country not in SUPPORTED_COUNTRIES:
            return jsonify({"error": f"Unknown country: {country}"}), 400
        if not company:
            return jsonify({"error": "company is required"}), 400

        from relocation_jobs.v2.catalog.repo import get_company

        if get_company(country, company) is None:
            return jsonify({"error": f"Company not found: {company}"}), 404

        try:
            message, new_jobs = run_single_company_fetch(country, company)
        except RuntimeError as exc:
            return jsonify({"error": str(exc)}), 503
        except LookupError as exc:
            return jsonify({"error": str(exc)}), 400

        return jsonify({
            "ok": True,
            "country": country,
            "company": company,
            "file": COUNTRY_ARCHIVE_FILENAMES.get(country, ""),
            "new_jobs": new_jobs,
            "message": message,
            "label": COUNTRY_LABELS.get(country, country),
        })

