from __future__ import annotations

from dataclasses import dataclass
from datetime import datetime, timezone

from relocation_jobs.core.job_identity import (
    job_idempotency_key,
    job_idempotency_key_for_job,
    stamp_job_identity,
)


@dataclass
class _ScrapeMergeResult:
    jobs: list[dict]
    preserved: int = 0
    new_count: int = 0
    seen_keys: set[str] | None = None

    def __post_init__(self) -> None:
        if self.seen_keys is None:
            self.seen_keys = set()


def now_iso() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat()


def _copy_location_fields(target: dict, *sources: dict) -> None:
    location = ""
    locations = None
    for source in sources:
        if not location:
            location = (source.get("location") or "").strip()
        if locations is None and source.get("locations"):
            locations = source.get("locations")
    if location:
        target["location"] = location
    if locations:
        target["locations"] = locations


def _index_existing_by_key(existing: list[dict]) -> dict[str, dict]:
    by_key: dict[str, dict] = {}
    for job in existing:
        key = job_idempotency_key_for_job(job)
        if not key:
            continue
        prev = by_key.get(key)
        if prev is None or (job.get("fetched") or "9999") < (prev.get("fetched") or "9999"):
            by_key[key] = job
    return by_key


def _merge_preserved_job(old: dict, job: dict, key: str, seen_at: str) -> dict:
    merged_job: dict = {
        "title": job.get("title") or old.get("title", ""),
        "url": old.get("url") or job.get("url", ""),
        "idempotency_key": key,
    }
    merged_job["fetched"] = old.get("fetched") or job.get("fetched") or seen_at
    merged_job["last_seen"] = old.get("last_seen") or old.get("fetched") or seen_at
    if old.get("visa_sponsorship") is not None:
        merged_job["visa_sponsorship"] = old["visa_sponsorship"]
    elif job.get("visa_sponsorship") is not None:
        merged_job["visa_sponsorship"] = job["visa_sponsorship"]
    _copy_location_fields(merged_job, job, old)
    return merged_job


def _merge_new_job(job: dict, key: str, seen_at: str) -> dict:
    merged_job = dict(job)
    merged_job["idempotency_key"] = key
    merged_job["fetched"] = merged_job.get("fetched") or seen_at
    merged_job["last_seen"] = seen_at
    return merged_job


def _merge_scraped_jobs(
    scraped: list[dict],
    by_key: dict[str, dict],
    seen_at: str,
) -> _ScrapeMergeResult:
    result = _ScrapeMergeResult(jobs=[])
    for job in scraped:
        key = job_idempotency_key(job.get("url", ""))
        if not key or key in result.seen_keys:
            continue
        result.seen_keys.add(key)
        if key in by_key:
            result.jobs.append(_merge_preserved_job(by_key[key], job, key, seen_at))
            result.preserved += 1
        else:
            result.jobs.append(_merge_new_job(job, key, seen_at))
            result.new_count += 1
    return result


def _append_stale_jobs(by_key: dict[str, dict], seen_keys: set[str]) -> tuple[list[dict], int]:
    stale: list[dict] = []
    for key, old in by_key.items():
        if key in seen_keys:
            continue
        kept = dict(old)
        stamp_job_identity(kept)
        stale.append(kept)
    return stale, len(stale)


def merge_matching_jobs(
    existing: list[dict],
    scraped: list[dict],
) -> tuple[list[dict], int, int, int]:
    seen_at = now_iso()
    by_key = _index_existing_by_key(existing)
    scraped_result = _merge_scraped_jobs(scraped, by_key, seen_at)
    stale_jobs, stale_kept = _append_stale_jobs(by_key, scraped_result.seen_keys)
    merged = scraped_result.jobs + stale_jobs
    for job in merged:
        stamp_job_identity(job)
    return merged, scraped_result.preserved, scraped_result.new_count, stale_kept

